# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

from ariadne import gql, make_executable_schema, QueryType, ObjectType
from ariadne.constants import PLAYGROUND_HTML
from flask import Flask, request, jsonify, g
from functools import wraps

# Mock data
users_data = [
    {
        "id": "1",
        "username": "john_doe",
        "bio": "Python developer",
        "email": "john@example.com",
        "phone": "123-456-7890",
        "address": "123 Main St"
    },
    {
        "id": "2",
        "username": "jane_smith",
        "bio": "Web developer",
        "email": "jane@example.com",
        "phone": "098-765-4321",
        "address": "456 Oak Ave"
    }
]

posts_data = [
    {
        "id": "1",
        "title": "First Post",
        "content": "This is the first post",
        "author_id": "1"
    },
    {
        "id": "2",
        "title": "Second Post",
        "content": "This is the second post",
        "author_id": "2"
    }
]

# GraphQL schema
type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        user(id: ID!): User
        users: [User!]!
        posts: [Post!]!
        post(id: ID!): Post
    }
""")

# Resolvers
query = QueryType()

@query.field("user")
def resolve_user(_, info, id):
    user = next((u for u in users_data if u["id"] == id), None)
    return user

@query.field("users")
def resolve_users(_, info):
    return users_data

@query.field("posts")
def resolve_posts(_, info):
    return posts_data

@query.field("post")
def resolve_post(_, info, id):
    post = next((p for p in posts_data if p["id"] == id), None)
    if post:
        author = next((u for u in users_data if u["id"] == post["author_id"]), None)
        post["author"] = author
    return post

# Types
user = ObjectType("User")
post = ObjectType("Post")

@user.field("email")
def resolve_user_email(user_obj, info):
    # This will be handled by middleware for permissions
    return user_obj.get("email")

@user.field("phone")
def resolve_user_phone(user_obj, info):
    return user_obj.get("phone")

@user.field("address")
def resolve_user_address(user_obj, info):
    return user_obj.get("address")

@post.field("author")
def resolve_post_author(post_obj, info):
    author = next((u for u in users_data if u["id"] == post_obj["author_id"]), None)
    return author

# Create schema
schema = make_executable_schema(type_defs, [query, user, post])

# Flask app
app = Flask(__name__)

# Middleware for authentication
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Mock authentication - in reality this would check tokens/cookies
        current_user = next((u for u in users_data if u["id"] == "1"), None)
        g.current_user = current_user
        return f(*args, **kwargs)
    return decorated_function

@app.route("/graphql", methods=["GET", "POST"])
@require_auth
def graphql_server():
    if request.method == "GET":
        return PLAYGROUND_HTML, 200
    
    data = request.get_json()
    query = data.get("query")
    variables = data.get("variables")
    
    if not query:
        return jsonify({"error": "No query provided"}), 400
    
    result = schema.execute_query(
        query,
        variable_values=variables,
        context_value={"current_user": g.current_user}
    )
    
    return jsonify(result.data), 200

if __name__ == "__main__":
    app.run(debug=True)